export const meta = {
  name: 'primality_check_17',
  description: 'Run two parallel primality checks for 17, tolerate one failure, synthesize surviving evidence',
  phases: [{ title: 'Check' }, { title: 'Synthesize' }]
};

phase('Check');

const N = 17;

const checks = await parallel([
  () => agent(
    `Determine whether the integer ${N} is prime. Method: trial division by every integer d with 2 <= d <= floor(sqrt(${N})). Show which divisors you test and the remainder. Then give a definitive verdict.`,
    {
      label: 'checker-trial-division',
      tier: 'small',
      schema: {
        type: 'object',
        properties: {
          number: { type: 'integer' },
          prime: { type: 'boolean' },
          method: { type: 'string' },
          reasoning: { type: 'string' }
        },
        required: ['number', 'prime', 'method', 'reasoning']
      }
    }
  ),
  () => agent(
    `Determine whether the integer ${N} is prime. Method: directly test divisibility by the candidate prime factors 2, 3, 5, 7 (the primes up to sqrt(${N})). Report each test and the remainder, then give a definitive verdict.`,
    {
      label: 'checker-divisor-probe',
      tier: 'small',
      schema: {
        type: 'object',
        properties: {
          number: { type: 'integer' },
          prime: { type: 'boolean' },
          method: { type: 'string' },
          reasoning: { type: 'string' }
        },
        required: ['number', 'prime', 'method', 'reasoning']
      }
    }
  )
]);

const evidence = checks.filter((c) => c !== null);
const failedChecks = checks.length - evidence.length;

phase('Synthesize');

// Tolerate failure: if at least one check survived, synthesize from it.
if (evidence.length === 0) {
  return {
    prime: null,
    evidence: 'All primality checks failed; no surviving evidence.',
    failedChecks
  };
}

const synthesis = await agent(
  `You are synthesizing independent primality-check results for the integer ${N}. Surviving evidence (as JSON): ${JSON.stringify(evidence)}. ` +
    `Reconcile the checks into ONE verdict. Produce a single concise combined evidence string summarizing the methods and the agreed conclusion. ` +
    `The number of checks that failed is ${failedChecks}.`,
  {
    label: 'synthesize-verdict',
    tier: 'big',
    schema: {
      type: 'object',
      properties: {
        prime: { type: 'boolean' },
        evidence: { type: 'string' }
      },
      required: ['prime', 'evidence']
    }
  }
);

// failedChecks is ground truth computed from actual failures; prime/evidence come from synthesis.
return {
  prime: synthesis ? synthesis.prime : null,
  evidence: synthesis ? synthesis.evidence : 'Synthesis failed.',
  failedChecks
};

